sys_sg_write_back_action_item.execution_script:
(function WriteBackAction(input) {
    //Type appropriate comment here, and begin script below
	if(input.u_reviewer_signed != 'true'){
		gs.addErrorMessage('You must check the signed checkbox before submitting this task');
		return false;
	}

	var current = new GlideRecord('x_153465_discovert_route_task_instance');
	current.get(input.sys_id);
	current.u_reviewer_signed = input.u_reviewer_signed;	
	current.comments_dt =input.reviewer_comments;

	new Task_uiAction().uiAction_UpdateTaskAndResponseLog('Concurred & signed', 'concur_sign', current);	
})(input);
